static inline uint32_t GetNumel(const gert::Shape *shape) {
    uint32_t n = 1;
    for (int i = 0; i < shape->GetOriginShape().GetDimNum(); ++i) {
        n *= static_cast<uint32_t>(shape->GetOriginShape().GetDim(i));
    }
